def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    # Identify main subject (typically the airport)
    subjects = list(subject_map.keys())
    main_subject = subjects[0] if len(subjects) == 1 else None

    # Build sentence parts for main subject
    main_sentence_parts = []
    secondary_sentences = []

    for subject, triples in subject_map.items():
        for predicate, obj in triples:
            if subject == main_subject:
                if predicate == "cityServed":
                    main_sentence_parts.append(f"serves the city of {obj}")
                elif predicate == "mayor":
                    main_sentence_parts.append(f"has a mayor named {obj}")
                elif predicate == "isPartOf":
                    main_sentence_parts.append(f"is part of {obj}")
                elif predicate == "operatingOrganisation":
                    main_sentence_parts.append(f"is operated by {obj}")
                elif predicate == "location":
                    main_sentence_parts.append(f"is located in {obj}")
                elif predicate == "elevationAboveTheSeaLevel":
                    main_sentence_parts.append(f"has an elevation of {obj} metres above sea level")
                elif predicate == "runwayLength":
                    main_sentence_parts.append(f"has a runway length of {obj} metres")
                elif predicate == "country":
                    main_sentence_parts.append(f"is located in {obj}")
                elif predicate == "capital":
                    main_sentence_parts.append(f"has a capital of {obj}")
                elif predicate == "language":
                    main_sentence_parts.append(f"has an official language of {obj}")
                elif predicate == "leader":
                    main_sentence_parts.append(f"has a leader named {obj}")
                elif predicate == "owner":
                    main_sentence_parts.append(f"is owned by {obj}")
                elif predicate == "1stRunwayLengthFeet":
                    main_sentence_parts.append(f"has a first runway length of {obj} feet")
                elif predicate == "1stRunwaySurfaceType":
                    main_sentence_parts.append(f"has a first runway surface type of {obj}")
                elif predicate == "3rdRunwayLengthFeet":
                    main_sentence_parts.append(f"has a third runway length of {obj} feet")
                elif predicate == "icaoLocationIdentifier":
                    main_sentence_parts.append(f"has an ICAO location identifier of {obj}")
                elif predicate == "locationIdentifier":
                    main_sentence_parts.append(f"has a location identifier of {obj}")
                elif predicate == "elevationAboveTheSeaLevelInFeet":
                    main_sentence_parts.append(f"has an elevation of {obj} feet above sea level")
                elif predicate == "iataLocationIdentifier":
                    main_sentence_parts.append(f"has an IATA location identifier of {obj}")
                elif predicate == "nativeName":
                    main_sentence_parts.append(f"has a native name of {obj}")
                elif predicate == "leaderParty":
                    main_sentence_parts.append(f"has a leader party of {obj}")
                else:
                    # General case: use natural phrasing for attributes
                    normalized_predicate = predicate.replace("1stRunwayLengthFeet", "first runway length") \
                                                  .replace("3rdRunwayLengthFeet", "third runway length") \
                                                  .replace("elevationAboveTheSeaLevel", "elevation") \
                                                  .replace("elevationAboveTheSeaLevelInFeet", "elevation") \
                                                  .replace("runwayLength", "runway length")
                    main_sentence_parts.append(f"has a {normalized_predicate} of {obj}")
            else:
                # Handle secondary subjects (e.g., cities, countries) and link them to main subject
                if predicate == "country" and main_subject:
                    for main_triple in subject_map[main_subject]:
                        if main_triple[0] == "location" and main_triple[1] == subject:
                            # Update main sentence: replace "is located in [city]" with "is located in [city], which is in [country]"
                            for i, part in enumerate(main_sentence_parts):
                                if f"is located in {subject}" in part:
                                    main_sentence_parts[i] = part.replace(f"is located in {subject}", f"is located in {subject}, which is in {obj}")
                            break
                elif predicate == "isPartOf" and main_subject:
                    for main_triple in subject_map[main_subject]:
                        if main_triple[0] == "location" and main_triple[1] == subject:
                            for i, part in enumerate(main_sentence_parts):
                                if f"is located in {subject}" in part:
                                    main_sentence_parts[i] = part.replace(f"is located in {subject}", f"is located in {subject}, which is part of {obj}")
                            break
                elif predicate == "language" and main_subject:
                    for main_triple in subject_map[main_subject]:
                        if main_triple[0] == "country" and main_triple[1] == subject:
                            secondary_sentences.append(f"The country {subject} has an official language of {obj}")
                            break
                elif predicate == "leader" and main_subject:
                    for main_triple in subject_map[main_subject]:
                        if main_triple[0] == "country" and main_triple[1] == subject:
                            secondary_sentences.append(f"The country {subject} has a leader named {obj}")
                            break

    # Construct final sentence
    result = ""
    if main_sentence_parts:
        result = f"{main_subject} " + ", ".join(main_sentence_parts)

    if secondary_sentences:
        if result:
            result += " and "
        result += " and ".join(secondary_sentences)

    return result + "."

